import{_ as r}from"./chunks/DemoViewer.vue_vue_type_script_setup_true_lang.DAQ2Gs41.js";import{x as i,y as t,z as n,A as s}from"./chunks/theme.BnJirLdI.js";import{u as o}from"./chunks/link-icons.fvmyrjZg.js";import{a3 as l,o as c,c as h,p as a,a as p,v as d,ah as v}from"./chunks/framework.cbxun9lb.js";import"./chunks/index.Difenjld.js";const _=JSON.parse('{"title":"JSON Canvas Viewer","titleTemplate":"Library Suite to Render JSON Canvas in Browsers","description":"JSON Canvas Viewer is a front-end library that ships an extensible viewer for JSON Canvas, with easy integration with any existing frameworks and paradigms.","frontmatter":{"layout":"project","title":"JSON Canvas Viewer","titleTemplate":"Library Suite to Render JSON Canvas in Browsers","description":"JSON Canvas Viewer is a front-end library that ships an extensible viewer for JSON Canvas, with easy integration with any existing frameworks and paradigms.","logo":"https://github.com/hesprs/json-canvas-viewer/raw/main/assets/logo.svg","links":[{"name":"GitHub Repository","url":"https://github.com/hesprs/json-canvas-viewer","color":"#010409"},{"name":"npm","url":"https://www.npmjs.com/package/json-canvas-viewer","color":"#EA2039"},{"name":"Documentation","url":"https://github.com/hesprs/json-canvas-viewer/wiki","color":"#425aef"},{"name":"JSON Canvas","url":"https://jsoncanvas.org","color":"#8B0A5F"}],"head":[["meta",{"name":"keywords","content":"JSON Canvas, JSON Canvas Viewer, Obsidian, Obsidian Canvas, visuallization, React component, Vue component, Preact component, npm library, JavaScript, TypeScript"}]]},"headers":[],"relativePath":"projects/json-canvas-viewer.md","filePath":"en/projects/json-canvas-viewer.md","lastUpdated":1777982901000}'),u={name:"projects/json-canvas-viewer.md"},y=l({...u,setup(m){return o({"GitHub Repository":s,npm:n,Documentation:t,"JSON Canvas":i}),(f,e)=>(c(),h("div",null,[e[0]||(e[0]=a("h2",{id:"demo",tabindex:"-1"},[p("Demo "),a("a",{class:"header-anchor",href:"#demo","aria-label":"Permalink to “Demo”"},"​")],-1)),d(r),e[1]||(e[1]=v('<p>Above illustration of the architecture of JSON Canvas Viewer is an instance of itself, with modules <a href="https://github.com/hesprs/json-canvas-viewer/wiki/3-%F0%9F%A7%A9-Modules#minimap" target="_blank" rel="noreferrer"><code>Minimap</code></a>, <a href="https://github.com/hesprs/json-canvas-viewer/wiki/3-%F0%9F%A7%A9-Modules#controls" target="_blank" rel="noreferrer"><code>Controls</code></a>, and <a href="https://github.com/hesprs/json-canvas-viewer/wiki/3-%F0%9F%A7%A9-Modules#mistouch-preventer" target="_blank" rel="noreferrer"><code>MistouchPreventer</code></a> loaded.</p><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to “Introduction”">​</a></h2><p><a href="https://obsidian.md" target="_blank" rel="noreferrer">Obsidian</a> ships a powerful tool called <a href="https://jsoncanvas.org" target="_blank" rel="noreferrer">JSON Canvas</a>, it enables me to think in a non-linear style, perfect for usages like complex state machines or dependency graphs. While it&#39;s sufficient for personal use, it&#39;s hard to share with others since there&#39;s no mature way to view it outside Obsidian.</p><p><code>JSON Canvas Viewer</code> comes to solve this problem, it is a TypeScript-based viewer for JSON Canvas files that enables users to view and interact with canvases directly in a browser, or embed the viewer in websites with ease. It is built without a framework so it is easily embeddable into any framework.</p><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to “Features”">​</a></h2><ul><li>View JSON Canvas files (<code>.canvas</code>) in a web browser</li><li>Embed into websites easily</li><li>Interactive pan and zoom functionality</li><li>Can display 100% of canvas features described in the <a href="https://jsoncanvas.org/spec/1.0/" target="_blank" rel="noreferrer">official spec</a></li><li>Responsive design with mobile and touchpad adaptation</li><li>Supports Lazy loading</li><li>TypeScript native</li><li>Modern aesthetics with light and dark mode support</li><li>A <a href="https://github.com/hesprs/json-canvas-viewer/wiki/1-%F0%9F%9A%80-Quick-Start#-chimpanzee-version" target="_blank" rel="noreferrer">chimp version</a> specially designed for fast trial is available</li><li>🔥 More performant than rendering canvases in Obsidian!</li><li>🧩 Out-of-the-box extensibility and tree-shaking powered by <a href="/researches/synthkernel">SynthKernel</a> architecture, current optional modules include: <ul><li><a href="https://github.com/hesprs/json-canvas-viewer/wiki/3-%F0%9F%A7%A9-Modules#minimap" target="_blank" rel="noreferrer"><code>Minimap</code></a> for easy navigation</li><li><a href="https://github.com/hesprs/json-canvas-viewer/wiki/3-%F0%9F%A7%A9-Modules#controls" target="_blank" rel="noreferrer"><code>Controls</code></a> displays zoom in/out and fullscreen buttons</li><li><a href="https://github.com/hesprs/json-canvas-viewer/wiki/3-%F0%9F%A7%A9-Modules#mistouch-preventer" target="_blank" rel="noreferrer"><code>MistouchPreventer</code></a> prevents the canvas from intercepting page scroll.</li><li><a href="https://github.com/hesprs/json-canvas-viewer/wiki/3-%F0%9F%A7%A9-Modules#debug-panel" target="_blank" rel="noreferrer"><code>DebugPanel</code></a> displays scale and position data.</li></ul></li></ul><h2 id="integration" tabindex="-1">Integration <a class="header-anchor" href="#integration" aria-label="Permalink to “Integration”">​</a></h2><p>JSON Canvas Viewer currently can work seamlessly with the following techstacks / technologies (including but not limited to):</p><ul><li>✅ Vanilla JS/TS: <a href="https://github.com/hesprs/json-canvas-viewer/wiki/1-%F0%9F%9A%80-Quick-Start#vanilla-jsts" target="_blank" rel="noreferrer">natural support</a> - <code>json-canvas-viewer</code></li><li>✅ Prerendering: <a href="https://github.com/hesprs/json-canvas-viewer/wiki/4-%F0%9F%96%87%EF%B8%8F-Prerendering" target="_blank" rel="noreferrer"><code>renderToString</code></a> - <code>json-canvas-viewer</code></li><li>✅ Vite: <a href="https://github.com/hesprs/json-canvas-viewer/wiki/1-%F0%9F%9A%80-Quick-Start#vite" target="_blank" rel="noreferrer">Vite Plugin</a> - <code>vite-plugin-json-canvas</code></li><li>✅ Vue: <a href="https://github.com/hesprs/json-canvas-viewer/wiki/1-%F0%9F%9A%80-Quick-Start#vue" target="_blank" rel="noreferrer">Vue Component</a> - <code>@json-canvas-viewer/vue</code></li><li>✅ React: <a href="https://github.com/hesprs/json-canvas-viewer/wiki/1-%F0%9F%9A%80-Quick-Start#react" target="_blank" rel="noreferrer">React Component</a> - <code>@json-canvas-viewer/react</code></li><li>✅ Preact: <a href="https://github.com/hesprs/json-canvas-viewer/wiki/1-%F0%9F%9A%80-Quick-Start#preact" target="_blank" rel="noreferrer">Preact Component</a> - <code>@json-canvas-viewer/preact</code></li></ul><p>For more about JSON Canvas Viewer, please go to the <a href="https://github.com/hesprs/json-canvas-viewer" target="_blank" rel="noreferrer">GitHub Repo</a>.</p><h2 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to “License”">​</a></h2><p>JSON Canvas Viewer is licensed under the <a href="https://mit-license.org/" target="_blank" rel="noreferrer">MIT License</a>.</p>',12))]))}});export{_ as __pageData,y as default};
